import json
import pandas as pd

# Load the full result from the query
with open('./tmp/tmp_sda1l9.json', 'r') as f:
    packages_data = json.load(f)

# Filter for actual release versions and parse the JSON data
releases = []
for pkg in packages_data:
    try:
        version_info = json.loads(pkg['VersionInfo'])
        if version_info.get('IsRelease', False):
            releases.append({
                'Name': pkg['Name'],
                'Version': pkg['Version'],
                'Ordinal': version_info.get('Ordinal', 0)
            })
    except:
        continue

print('__RESULT__:')
print(json.dumps(releases[:100]))

