import json
import os
import re
from collections import defaultdict

# Read release versions data
releases_file = './tmp/tmp_7h8j5t.json'
if os.path.exists(releases_file):
    with open(releases_file, 'r') as f:
        releases_raw = json.load(f)
else:
    releases_raw = []

# Read project package version data  
ppv_file = './tmp/tmp_s9j2w1.json'
if os.path.exists(ppv_file):
    with open(ppv_file, 'r') as f:
        ppv_data = json.load(f)
else:
    ppv_data = []

# Read project info data
pi_file = './tmp/tmp_n7k3y9.json'
if os.path.exists(pi_file):
    with open(pi_file, 'r') as f:
        pi_data = json.load(f)
else:
    pi_data = []

# Parse releases to find latest version for each package
package_releases = defaultdict(list)
for pkg in releases_raw:
    try:
        version_info = json.loads(pkg['VersionInfo'])
        if version_info.get('IsRelease', False):
            package_releases[pkg['Name']].append({
                'Version': pkg['Version'],
                'Ordinal': version_info.get('Ordinal', 0),
                'Links': pkg.get('Links', '')
            })
    except:
        continue

# Find latest release for each package
latest_releases = {}
for name, versions in package_releases.items():
    if versions:
        latest = max(versions, key=lambda x: x['Ordinal'])
        latest_releases[name] = latest

# Create mapping from project name to project info
project_info_map = {}
for proj in pi_data:
    try:
        # Extract project name from Project_Information field
        proj_name_match = re.search(r'project\s+([\w-]+/[\w-]+)', proj['Project_Information'], re.I)
        if proj_name_match:
            proj_name = proj_name_match.group(1)
            # Extract star count
            stars_match = re.search(r'([\d,]+)\s+stars', proj['Project_Information'])
            if stars_match:
                stars = int(stars_match.group(1).replace(',', ''))
                project_info_map[proj_name] = {
                    'stars': stars,
                    'info': proj['Project_Information']
                }
    except:
        continue

# Match packages with projects and get stars
matched_packages = []
for ppv in ppv_data:
    pkg_name = ppv['Name']
    if pkg_name in latest_releases:
        latest_ver = latest_releases[pkg_name]
        if ppv['Version'] == latest_ver['Version']:
            proj_name = ppv['ProjectName']
            if proj_name in project_info_map:
                matched_packages.append({
                    'PackageName': pkg_name,
                    'Version': latest_ver['Version'],
                    'ProjectName': proj_name,
                    'Stars': project_info_map[proj_name]['stars']
                })

# Sort by stars and get top 5
top_packages = sorted(matched_packages, key=lambda x: x['Stars'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps({
    'matched_packages': len(matched_packages),
    'top_5_packages': top_packages
}, indent=2))

